    const candidates = Array.from(document.querySelectorAll('input[placeholder="Pesquisar"]'));































































































































































































































































































































































































































































































































    const mainCandidate = candidates.find((el) => isVisible(el) && !isInSidebar(el));































































































































































































































































































































































































































































































































    const anyVisible = candidates.find((el) => isVisible(el));































































































































































































































































































































































































































































































































