const extractRowFromCustomersByUsuario = async (pageInstance, usuario) => {
  if (!usuario) return null;

  const row = await pageInstance.evaluate((usuarioValue) => {
    const normalize = (value) => String(value || "").replace(/\s+/g, " ").trim();
    const target = String(usuarioValue || "").trim();
    if (!target) return null;

    const root =
      document.querySelector(".el-table__body-wrapper") ||
      document.querySelector(".el-table__body") ||
      document.querySelector("main") ||
      document.body;

    const rowEls = Array.from(root.querySelectorAll("tr, [role='row'], .el-table__row")).filter(Boolean);
    if (!rowEls.length) return null;

    const matches = rowEls.filter((el) => {
      const txt = normalize(el.innerText || el.textContent);
      return txt && txt.includes(target);
    });

    if (!matches.length) return null;

    const chosen = matches
      .map((el) => {
        const txt = normalize(el.innerText || el.textContent);
        const score =
          (/(Plano:|Conex|Venc|R\$)/i.test(txt) ? 10 : 0) +
          (txt.split(" ").length >= 6 ? 2 : 0) -
          Math.min(5, Math.floor(txt.length / 400));
        return { el, txt, score };
      })
      .sort((a, b) => b.score - a.score)[0];

    if (!chosen) return null;
    const rowText = chosen.txt;

    const phoneCandidates = Array.from(chosen.el.querySelectorAll("a"))
      .map((a) => (a.textContent || "").replace(/\D/g, ""))
      .filter(Boolean);

    let phone =
      phoneCandidates.find((v) => v.startsWith("55") && v.length >= 12 && v.length <= 14) ||
      null;

    if (!phone) {
      const raw = phoneCandidates.find((v) => v.length === 10 || v.length === 11) || null;
      phone = raw ? `55${raw}` : null;
    }

    if (!phone) {
      const m = rowText.replace(/\D/g, "").match(/55\d{10,12}/);
      phone = m ? m[0] : null;
    }

    const planMatch = rowText.match(/\[[^\]]+\]\s*[^\r\n]+/);
    const planoAtual = planMatch ? planMatch[0].trim() : null;

    const conexoesMatch = rowText.match(/Conex[^:]*:\s*(\d+)/i);
    const conexoes = conexoesMatch ? Number(conexoesMatch[1]) : null;

    const vencimentoMatch = rowText.match(/\d{2}\/\d{2}\/\d{4},?\s*\d{2}:\d{2}:\d{2}/);
    const vencimento = vencimentoMatch ? vencimentoMatch[0] : null;

    const valorMatch = rowText.match(/R\$\s*[\d.,]+/);
    const valor = valorMatch ? valorMatch[0].replace(/\s+/g, " ").trim() : null;

    const situacao = /Inativo/i.test(rowText) ? "INATIVO" : /Ativo/i.test(rowText) ? "ATIVO" : null;

    return {
      usuario: target,
      phone,
      planoAtual,
      conexoes,
      vencimento,
      valor,
      situacao,
    };
  }, usuario).catch(() => null);

  if (!row) return null;
  if (!row.phone && !row.usuario) return null;
  return row;
};

export const fetchPainelCustomersByDueDate = async ({ dueDate, onLog, maxPages, maxItems, countOnly = false } = {}) =>
  withLock(async () => {
    const targetDate = normalizeDueDateValue(dueDate);
    if (!targetDate) {
      throw new Error('Missing due date');
    }
    const dueDateDiag = await startDueDateDiagnostics(onLog);
    const pageInstance = dueDateDiag?.page || await ensureContext(onLog);
    try {
      await ensureLoggedIn(pageInstance, onLog, dueDateDiag?.context);
      await navigateToDashboard(pageInstance, onLog);
      await handleCloudflareChallenge(pageInstance, onLog);
      await ensureDashboardSectionVisible(pageInstance, onLog);
      const dashboardRows = await extractDashboardUsersByDueDate(pageInstance, targetDate, onLog);
      if (!dashboardRows.length) {
        onLog?.(`Dashboard: nenhum cliente encontrado para ${targetDate}.`);
        return { total: 0, pages: 0, rows: [], dueDate: targetDate };
      }
      if (countOnly) {
        onLog?.(`Dashboard: retornando somente contagem para ${targetDate}.`);
        return { total: dashboardRows.length, pages: 1, rows: dashboardRows, dueDate: targetDate };
      }
      await navigateToCustomers(pageInstance, onLog);
      await setItemsPerPage(pageInstance, onLog, 100);
      const limitItems = typeof maxItems === 'number' ? maxItems : 0;
      const collectedRows = [];
      for (const item of dashboardRows) {
        if (limitItems > 0 && collectedRows.length >= limitItems) {
          onLog?.('Limite de clientes atingido.');
          break;
        }
        const usuario = item?.usuario;
        if (!usuario) {
          continue;
        }
        await clearSearch(pageInstance, onLog);
        await searchCustomer(pageInstance, usuario);
        await pageInstance.waitForResponse(
          (r) => r.url().includes('/api/customers') && r.request().method() === 'GET',
          { timeout: DUE_DATE_SEARCH_WAIT_MS },
        ).catch(() => {});
        let row = await extractRowFromCustomersByUsuario(pageInstance, usuario);
        if (!row) {
          const rows = await extractRowsFromPage(pageInstance);
          row = rows[0] || null;
        }
        if (!row) {
          onLog?.(`Cliente nao encontrado para ${usuario}.`);
          continue;
        }
        collectedRows.push({
          ...row,
          usuario: row.usuario || usuario,
          vencimento: row.vencimento || item.vencimento || targetDate,
        });
        onLog?.(`Cliente coletado: ${usuario}.`);
      }
      return { total: collectedRows.length, pages: 1, rows: collectedRows, dueDate: targetDate };
    } finally {
      await finalizeDueDateDiagnostics(dueDateDiag, pageInstance, onLog);
    }
  });
